app = Flask(__name__)

# Load JWT secret from environment variable - NEVER hardcode
JWT_SECRET = os.environ.get('JWT_SECRET')
if not JWT_SECRET:
    raise ValueError("JWT_SECRET environment variable must be set")

JWT_ALGORITHM = os.environ.get('JWT_ALGORITHM', 'HS256')
BACKEND_SERVICE_URL = os.environ.get('BACKEND_SERVICE_URL', 'http://localhost:5001')

# Allowlist of valid algorithms to prevent algorithm confusion attacks
ALLOWED_ALGORITHMS = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']

# Allowlist of allowed backend endpoints
ALLOWED_ENDPOINTS = [
    r'^/api/users/[a-zA-Z0-9_-]+$',
    r'^/api/data$',
    r'^/api/resources/[a-zA-Z0-9_-]+$'
]

def validate_endpoint(path):
    """Validate that the requested endpoint is in the allowlist"""
    for pattern in ALLOWED_ENDPOINTS:
        if re.match(pattern, path):
            return True
    return False

def validate_token(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = None
        auth_header = request.headers.get('Authorization')
        
        if not auth_header:
            return jsonify({'error': 'Authorization header missing'}), 401
        
        # Validate Authorization header format
        parts = auth_header.split()
        if len(parts) != 2 or parts[0].lower() != 'bearer':
            return jsonify({'error': 'Invalid authorization header format. Use: Bearer <token>'}), 401
        
        token = parts[1]
        
        # Validate token is not empty and has reasonable length
        if not token or len(token) > 2048:
            return jsonify({'error': 'Invalid token'}), 401
        
        try:
            # SECURE: Verify JWT signature with verify=True (NOT False)
            # Validate algorithm is in allowlist
            if JWT_ALGORITHM not in ALLOWED_ALGORITHMS:
                return jsonify({'error': 'Invalid JWT algorithm configured'}), 500
            
            # Decode and VERIFY the token
            payload = jwt.decode(
                token,
                JWT_SECRET,
                algorithms=[JWT_ALGORITHM],  # Explicit algorithm to prevent confusion attacks
                options={
                    'verify_signature': True,  # ALWAYS verify signature
                    'verify_exp': True,  # Verify expiration
                    'verify_nbf': True,  # Verify not before
                    'verify_iat': True,  # Verify issued at
                    'require_exp': True,  # Require expiration claim
                }
            )
            
            # Validate required claims exist
            required_claims = ['sub', 'exp', 'iat']
            for claim in required_claims:
                if claim not in payload:
                    return jsonify({'error': f'Missing required claim: {claim}'}), 401
            
            # Validate expiration is reasonable (not too far in future)
            exp_timestamp = payload.get('exp')
            max_future = datetime.utcnow() + timedelta(days=30)
            if datetime.fromtimestamp(exp_timestamp) > max_future:
                return jsonify({'error': 'Token expiration too far in future'}), 401
            
            # Validate user ID format (alphanumeric, underscore, hyphen only)
            user_id = payload.get('sub', '')
            if not re.match(r'^[a-zA-Z0-9_-]+$', user_id):
                return jsonify({'error': 'Invalid user identifier format'}), 401
            
            # Store validated claims in request context
            request.user_claims = payload
            
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError as e:
            return jsonify({'error': 'Invalid token'}), 401
        except Exception as e:
            # Don't leak internal error details
            app.logger.error(f"Token validation error: {str(e)}")
            return jsonify({'error': 'Authentication failed'}), 401
        
        return f(*args, **kwargs)
    
    return decorated_function

@app.route('/api/<path:endpoint>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
@validate_token
def gateway(endpoint):
    """Forward authenticated requests to backend services"""
    
    # Validate endpoint against allowlist
    full_path = f"/api/{endpoint}"
    if not validate_endpoint(full_path):
        return jsonify({'error': 'Endpoint not allowed'}), 403
    
    # Extract validated user claims
    user_claims = request.user_claims
    
    # Prepare headers for backend service
    # Only forward safe, validated claims
    backend_headers = {
        'X-User-ID': user_claims.get('sub', ''),
        'X-User-Email': user_claims.get('email', ''),
        'X-User-Roles': ','.join(user_claims.get('roles', [])) if isinstance(user_claims.get('roles'), list) else '',
        'Content-Type': request.headers.get('Content-Type', 'application/json')
    }
    
    # Sanitize and validate backend URL
    backend_url = f"{BACKEND_SERVICE_URL}/{endpoint}"
    
    # Validate backend URL doesn't contain malicious characters
    if not re.match(r'^https?://[a-zA-Z0-9.-]+(:[0-9]+)?/[a-zA-Z0-9/_-]*$', backend_url):
        return jsonify({'error': 'Invalid backend URL'}), 500
    
    try:
        # Forward request to backend service
        if request.method == 'GET':
            # Validate query parameters
            safe_params = {}
            for key, value in request.args.items():
                if re.match(r'^[a-zA-Z0-9_-]+$', key) and len(str(value)) < 1000:
                    safe_params[key] = value
            
            response = requests.get(
                backend_url,
                headers=backend_headers,
                params=safe_params,
                timeout=30,
                verify=True  # Verify SSL certificates
            )
        else:
            # Validate content type for POST/PUT/PATCH
            content_type = request.headers.get('Content-Type', '')
            if 'application/json' not in content_type:
                return jsonify({'error': 'Only application/json content type supported'}), 400
            
            # Limit request body size
            if request.content_length and request.content_length > 1048576:  # 1MB limit
                return jsonify({'error': 'Request body too large'}), 413
            
            response = requests.request(
                method=request.method,
                url=backend_url,
                headers=backend_headers,
                json=request.get_json(),
                timeout=30,
                verify=True
            )
        
        # Return backend response
        return Response(
            response.content,
            status=response.status_code,
            headers=dict(response.headers)
        )
        
    except requests.exceptions.Timeout:
        return jsonify({'error': 'Backend service timeout'}), 504
    except requests.exceptions.RequestException as e:
        app.logger.error(f"Backend request error: {str(e)}")
        return jsonify({'error': 'Backend service unavailable'}), 503
    except Exception as e:
        app.logger.error(f"Unexpected error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

